const expected = $env.AGENT_REACH_WEBHOOK_SECRET || '';
const runnerSecret = $env.AGENT_REACH_RUNNER_SECRET || expected;
const headers = $json.headers || {};
const fromWebhook = Object.keys(headers).length > 0;
if (expected && fromWebhook) {
  const auth = headers.authorization || headers.Authorization || '';
  const headerSecret = headers['x-agent-reach-secret'] || headers['X-Agent-Reach-Secret'] || '';
  if (auth !== `Bearer ${expected}` && headerSecret !== expected) {
    throw new Error('Unauthorized Agent Reach webhook call');
  }
}
const scheduleRequest = {
  sources: $env.AGENT_REACH_SOURCES || 'exa,official,rss',
  limitKeywords: Number($env.AGENT_REACH_LIMIT_KEYWORDS || 54),
  exaResults: Number($env.AGENT_REACH_EXA_RESULTS || 3),
  officialResults: Number($env.AGENT_REACH_OFFICIAL_RESULTS || 3),
  rssResults: Number($env.AGENT_REACH_RSS_RESULTS || 8),
};
const request = fromWebhook && $json.body && typeof $json.body === 'object' ? $json.body : scheduleRequest;
return [{
  json: {
    trigger: fromWebhook ? 'webhook' : 'schedule',
    runnerUrl: $env.AGENT_REACH_RUNNER_URL || 'http://host.docker.internal:8787/run',
    runnerSecret,
    request,
  }
}];

const result = $input.first().json;
return [{
  json: {
    ok: Boolean(result.ok),
    accepted: Boolean(result.accepted),
    args: result.args || [],
    exitCode: result.exitCode,
    summary: result.summary || null,
    stderr: result.stderr || '',
    completed_at: new Date().toISOString(),
  }
}];
